-- Weekly QA Counter v700 full restored Supabase setup
create extension if not exists pgcrypto;
create table if not exists public.allowed_users (id uuid primary key default gen_random_uuid(), email text unique not null, name text not null, is_active boolean not null default true, role text not null default 'qa', created_at timestamptz default now());
create table if not exists public.workstreams (id uuid primary key default gen_random_uuid(), name text not null, is_active boolean not null default true, created_at timestamptz default now());
create table if not exists public.qa_members (id uuid primary key default gen_random_uuid(), name text not null, email text, is_active boolean not null default true, created_at timestamptz default now());
create table if not exists public.agents (id uuid primary key default gen_random_uuid(), name text not null, workstream_id uuid references public.workstreams(id) on delete cascade, is_active boolean not null default true, created_at timestamptz default now());
create table if not exists public.weekly_settings (id uuid primary key default gen_random_uuid(), week_start date not null, workstream_id uuid references public.workstreams(id) on delete cascade, base_target int not null default 5, extra_if_fail int not null default 2, created_at timestamptz default now());
create table if not exists public.weekly_assignments (id uuid primary key default gen_random_uuid(), week_start date not null, qa_member_id uuid references public.qa_members(id) on delete set null, agent_id uuid references public.agents(id) on delete cascade, workstream_id uuid references public.workstreams(id) on delete cascade, fail_count int not null default 0, created_at timestamptz default now());
create table if not exists public.qa_counts (id uuid primary key default gen_random_uuid(), assignment_id uuid references public.weekly_assignments(id) on delete cascade, qa_date date not null, count int not null default 0, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.qa_count_logs (id uuid primary key default gen_random_uuid(), assignment_id uuid references public.weekly_assignments(id) on delete cascade, qa_date date not null, performed_by_qa_member_id uuid references public.qa_members(id) on delete set null, count_delta int not null, created_at timestamptz default now());
create table if not exists public.auditor_absences (id uuid primary key default gen_random_uuid(), qa_member_id uuid references public.qa_members(id) on delete cascade, covering_qa_member_id uuid references public.qa_members(id) on delete set null, leave_type text not null default 'PTO', start_date date not null default current_date, return_date date not null, status text not null default 'active', created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.assignment_transfers (id uuid primary key default gen_random_uuid(), absence_id uuid references public.auditor_absences(id) on delete cascade, assignment_id uuid references public.weekly_assignments(id) on delete cascade, original_qa_member_id uuid references public.qa_members(id) on delete set null, covering_qa_member_id uuid references public.qa_members(id) on delete set null, created_at timestamptz default now());
alter table public.allowed_users add column if not exists role text not null default 'qa';
alter table public.qa_members add column if not exists email text;
alter table public.weekly_assignments add column if not exists fail_count int not null default 0;
alter table public.weekly_assignments drop constraint if exists weekly_assignments_fail_count_nonnegative;
alter table public.weekly_assignments add constraint weekly_assignments_fail_count_nonnegative check (fail_count >= 0);
do $$ begin if to_regclass('public.fail_counts') is not null then execute 'with totals as (select assignment_id, coalesce(sum(fail_count), 0)::int as total_fail from public.fail_counts group by assignment_id) update public.weekly_assignments wa set fail_count = totals.total_fail from totals where wa.id = totals.assignment_id'; end if; end $$;
insert into public.workstreams (name,is_active) select 'T2 Privacy',true where not exists (select 1 from public.workstreams where lower(trim(name))='t2 privacy');
insert into public.workstreams (name,is_active) select 'T2 Privacy - Pilot',true where not exists (select 1 from public.workstreams where lower(trim(name))='t2 privacy - pilot');
update public.workstreams set is_active=true where lower(trim(name)) in ('t2 privacy','t2 privacy - pilot');
insert into public.qa_members (name,email,is_active) select 'Priyank','priyank@test.com',true where not exists (select 1 from public.qa_members where lower(trim(name))='priyank');
insert into public.qa_members (name,email,is_active) select 'Parth','parth@test.com',true where not exists (select 1 from public.qa_members where lower(trim(name))='parth');
update public.qa_members set is_active=true, email=case when lower(trim(name))='priyank' then 'priyank@test.com' when lower(trim(name))='parth' then 'parth@test.com' else email end where lower(trim(name)) in ('priyank','parth');
insert into public.allowed_users (email,name,is_active,role) select 'priyank@test.com','Priyank',true,'qa' where not exists (select 1 from public.allowed_users where lower(email)='priyank@test.com');
insert into public.allowed_users (email,name,is_active,role) select 'parth@test.com','Parth',true,'qa' where not exists (select 1 from public.allowed_users where lower(email)='parth@test.com');
insert into public.allowed_users (email,name,is_active,role) select 'admin@admin.com','Admin',true,'admin' where not exists (select 1 from public.allowed_users where lower(email)='admin@admin.com');
update public.allowed_users set is_active=true, role=case when lower(email)='admin@admin.com' then 'admin' else role end where lower(email) in ('priyank@test.com','parth@test.com','admin@admin.com');
do $$ declare ws_id uuid; n text; begin select id into ws_id from public.workstreams where lower(trim(name))='t2 privacy' limit 1; if ws_id is not null and not exists (select 1 from public.agents limit 1) then foreach n in array array['Kiran','Mark','Sagar','Bhanu','Bipin','Dave','Ruhi','Sneha','Vera','Vidhi'] loop insert into public.agents (name,workstream_id,is_active) values (n,ws_id,true); end loop; end if; end $$;
create unique index if not exists weekly_settings_unique_week_workstream on public.weekly_settings (week_start,workstream_id);
create unique index if not exists weekly_assignments_unique_week_agent_workstream on public.weekly_assignments (week_start,agent_id,workstream_id);
create unique index if not exists qa_counts_unique_assignment_date on public.qa_counts (assignment_id,qa_date);
create unique index if not exists assignment_transfers_unique_absence_assignment on public.assignment_transfers (absence_id,assignment_id);
do $$ declare t text; begin foreach t in array array['allowed_users','workstreams','qa_members','agents','weekly_settings','weekly_assignments','qa_counts','qa_count_logs','auditor_absences','assignment_transfers'] loop execute format('alter table public.%I enable row level security', t); execute format('drop policy if exists "qa tracker auth read" on public.%I', t); execute format('drop policy if exists "qa tracker auth insert" on public.%I', t); execute format('drop policy if exists "qa tracker auth update" on public.%I', t); execute format('drop policy if exists "qa tracker auth delete" on public.%I', t); execute format('create policy "qa tracker auth read" on public.%I for select to authenticated using (true)', t); execute format('create policy "qa tracker auth insert" on public.%I for insert to authenticated with check (true)', t); execute format('create policy "qa tracker auth update" on public.%I for update to authenticated using (true) with check (true)', t); execute format('create policy "qa tracker auth delete" on public.%I for delete to authenticated using (true)', t); end loop; end $$;
notify pgrst,'reload schema';
select 'weekly qa counter v700 setup complete' as status;
